  input            clock;
  input            reset_n;

  wire    [ 31: 0] readdata;

  assign readdata = address ? 1419000801 : 2899645186;

  always @(*) begin
    if (1'b0) begin
      readdata <= 32'hDEADBEEF;
    end
  end

endmodule
